// Cosmos DB EF Core 9 Breaking Changes — Required Fixes
// Apply these to your separate Cosmos DB project.
// =============================================================================

// --- FIX 1: Discriminator property renamed from "Discriminator" to "$type" ---
// Existing documents use "Discriminator". Preserve it explicitly:
//
//   protected override void OnModelCreating(ModelBuilder modelBuilder)
//   {
//       modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");
//   }

// --- FIX 2: id property no longer contains discriminator ---
// EF Core 8 stored id as "EntityType|KeyValue" (e.g. "Product|123").
// EF Core 9 stores just "123". Existing documents won't be found by FindAsync.
// Preserve the old format:
//
//   modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

// --- FIX 3: Sync I/O no longer supported ---
// Synchronous methods (SaveChanges, ToList, First, etc.) now throw.
// Replace ALL sync calls with async equivalents:
